const body=document.querySelector("body"),bodyBefore=document.createElement("div");function updateTime(){const e=document.querySelector(".animated-clock"),t=new Date,o=t.getHours().toString().padStart(2,"0"),d=t.getMinutes().toString().padStart(2,"0"),n=t.getSeconds().toString().padStart(2,"0");e.textContent=`${o}:${d}:${n}`}bodyBefore.classList.add("background"),body.insertBefore(bodyBefore,body.firstChild),document.addEventListener("mousemove",(e=>{const t=31*(e.clientX/window.innerWidth-.5),o=31*(e.clientY/window.innerHeight-.5);bodyBefore.style.backgroundImage="url('https://cdn.akamai.steamstatic.com/steamcommunity/public/images/items/1465680/ee46cc3b6988057d435be7e391472d46f278d87a.jpg')",bodyBefore.style.backgroundSize="cover",bodyBefore.style.width="100vw",bodyBefore.style.height="100vh",bodyBefore.style.position="fixed",bodyBefore.style.top="0",bodyBefore.style.left="0",bodyBefore.style.zIndex="-1",bodyBefore.style.transformOrigin="center center",bodyBefore.style.transform=`scale(1.05) translate(${t}px, ${o}px)`})),document.addEventListener("DOMContentLoaded",(function(){document.querySelectorAll(".profile-box, .social-box, .rounded-icon").forEach((function(e){e.classList.add("fadeIn")}))})),setInterval(updateTime,1e3),updateTime();
